"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import {
  api,
  type Category,
  type SubCategory,
  type MenuItem,
  normalizeSubCategories,
} from "@/lib/api";
import { COLORS } from "@/lib/theme";

const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:4000";
const TOAST_KEY = "items_toast";

type ViewMode = "items" | "categories" | "subcategories";

const TILE_COLORS = [
  { border: COLORS.primary, accent: COLORS.primary },
  { border: "#10b981", accent: "#10b981" },
  { border: "#f59e0b", accent: "#f59e0b" },
  { border: "#ef4444", accent: "#ef4444" },
  { border: "#8b5cf6", accent: "#8b5cf6" },
  { border: "#ec4899", accent: "#ec4899" },
];

function formatPesos(cents: number): string {
  return `₱${(cents / 100).toFixed(2)}`;
}

export function ItemsList() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [categories, setCategories] = useState<Category[]>([]);
  const [items, setItems] = useState<MenuItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [includeDeleted, setIncludeDeleted] = useState(
    searchParams.get("includeDeleted") === "1"
  );
  const [viewMode, setViewMode] = useState<ViewMode>("items");
  const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
  const [selectedSubCategoryId, setSelectedSubCategoryId] = useState<string | null>(
    null
  );

  const safeCategories = Array.isArray(categories) ? categories : [];

  useEffect(() => {
    const msg =
      typeof sessionStorage !== "undefined" ? sessionStorage.getItem(TOAST_KEY) : null;
    if (msg) {
      sessionStorage.removeItem(TOAST_KEY);
      setSuccess(msg);
      const t = setTimeout(() => setSuccess(""), 3000);
      return () => clearTimeout(t);
    }
  }, []);

  function refresh() {
    setLoading(true);
    Promise.all([api.getCategories(), api.getItems(includeDeleted)])
      .then(([cats, its]) => {
        setCategories(Array.isArray(cats) ? cats : []);
        setItems(Array.isArray(its) ? its : []);
      })
      .catch((e) => {
        setError(e instanceof Error ? e.message : "Failed to load");
        setCategories([]);
        setItems([]);
      })
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    setIncludeDeleted(searchParams.get("includeDeleted") === "1");
  }, [searchParams]);

  useEffect(() => {
    refresh();
  }, [includeDeleted]);

  useEffect(() => {
    if (
      safeCategories.length > 0 &&
      !selectedCategoryId &&
      (viewMode === "items" || viewMode === "subcategories")
    ) {
      setSelectedCategoryId(safeCategories[0]!.id);
    }
  }, [safeCategories.length, selectedCategoryId, viewMode]);

  function handleCategoryChange(categoryId: string) {
    setSelectedCategoryId(categoryId);
    setSelectedSubCategoryId(null);
  }

  function handleSubcategoryClick(sub: SubCategory) {
    setSelectedSubCategoryId(sub.id);
  }

  function handleBackToTiles() {
    setSelectedSubCategoryId(null);
  }

  async function handleDeleteItem(item: MenuItem) {
    if (!confirm(`Delete "${item.name}"?`)) return;
    setError("");
    setSuccess("");
    try {
      await api.deleteItem(item.id);
      setSuccess("Item deleted");
      refresh();
      setTimeout(() => setSuccess(""), 3000);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to delete");
    }
  }

  async function handleRestoreItem(item: MenuItem) {
    if (!confirm(`Restore "${item.name}"?`)) return;
    setError("");
    setSuccess("");
    try {
      await api.restoreItem(item.id);
      setSuccess("Item restored");
      refresh();
      setTimeout(() => setSuccess(""), 3000);
    } catch (e) {
      setError(e instanceof Error ? e.message : "Failed to restore");
    }
  }

  async function handleDeleteCategory(cat: Category) {
    if (!confirm(`Delete category "${cat.name}"?`)) return;
    setError("");
    try {
      await api.deleteCategory(cat.id);
      if (selectedCategoryId === cat.id) {
        setSelectedCategoryId(null);
        setSelectedSubCategoryId(null);
      }
      refresh();
    } catch (err: unknown) {
      const body = (err as { body?: { error?: string } })?.body;
      if (body?.error === "CATEGORY_NOT_EMPTY") {
        setError("Cannot delete: category has subcategories. Delete or move them first.");
      } else {
        setError(err instanceof Error ? err.message : "Failed");
      }
    }
  }

  async function handleDeleteSubCategory(sub: SubCategory) {
    if (!confirm(`Delete subcategory "${sub.name}"?`)) return;
    setError("");
    try {
      await api.deleteSubCategory(sub.id);
      if (selectedSubCategoryId === sub.id) {
        setSelectedSubCategoryId(null);
      }
      refresh();
    } catch (err: unknown) {
      const body = (err as { body?: { error?: string } })?.body;
      if (body?.error === "SUBCATEGORY_NOT_EMPTY") {
        setError("Cannot delete: subcategory has items. Delete or move them first.");
      } else {
        setError(err instanceof Error ? err.message : "Failed");
      }
    }
  }

  const currentCategory = safeCategories.find((c) => c.id === selectedCategoryId);
  const subcategories = currentCategory
    ? normalizeSubCategories(currentCategory.subCategories)
    : [];

  const filteredItems =
    selectedSubCategoryId && viewMode === "items"
      ? items.filter((i) => i.subCategoryId === selectedSubCategoryId)
      : [];

  const selectedSubcategory = subcategories.find((s) => s.id === selectedSubCategoryId);

  if (loading) {
    return (
      <div className="rounded border bg-gray-50 p-8 text-center text-gray-600">
        Loading…
      </div>
    );
  }

  return (
    <div
      className="flex flex-col overflow-hidden rounded-lg border border-gray-200"
      style={{ minHeight: 400, background: COLORS.bgDark }}
    >
      {/* Top bar: view mode toggle + include deleted + success/error */}
      <div
        className="flex flex-wrap items-center justify-between gap-3 px-4 py-2"
        style={{ background: COLORS.bgDarker, borderBottom: `1px solid ${COLORS.borderDark}` }}
      >
        <div className="flex flex-wrap items-center gap-3">
          <div className="flex rounded border" style={{ borderColor: COLORS.borderLight }}>
            {(["items", "categories", "subcategories"] as const).map((m) => (
              <button
                key={m}
                type="button"
                onClick={() => {
                  setViewMode(m);
                  if (m === "items") {
                    setSelectedSubCategoryId(null);
                  }
                }}
                style={{
                  padding: "8px 16px",
                  fontSize: 13,
                  fontWeight: viewMode === m ? "600" : "normal",
                  background: viewMode === m ? COLORS.primary : COLORS.bgPanel,
                  color: "#fff",
                  border: "none",
                  cursor: "pointer",
                  textTransform: "capitalize",
                }}
              >
                {m}
              </button>
            ))}
          </div>
          <label
            className="flex cursor-pointer items-center gap-2 text-sm"
            style={{ color: "#aaa" }}
          >
            <input
              type="checkbox"
              checked={includeDeleted}
              onChange={(e) => {
                const v = e.target.checked;
                setIncludeDeleted(v);
                const url = new URL(window.location.href);
                if (v) url.searchParams.set("includeDeleted", "1");
                else url.searchParams.delete("includeDeleted");
                router.replace(url.pathname + url.search, { scroll: false });
              }}
              className="rounded"
            />
            Show deleted
          </label>
        </div>
        {success && <p className="text-sm" style={{ color: "#22c55e" }}>{success}</p>}
        {error && <p className="text-sm" style={{ color: "#ef4444" }}>{error}</p>}
      </div>

      {/* Category Tabs (scrollable) */}
      <div
        className="overflow-x-auto px-4 py-3"
        style={{ borderBottom: `1px solid ${COLORS.borderDark}`, background: COLORS.bgDarker }}
      >
        <div className="flex gap-2">
          {safeCategories.length === 0 ? (
            <p style={{ color: "#666", fontSize: 14, margin: 0 }}>
              No categories. Create them in <Link href="/categories" className="underline" style={{ color: COLORS.primary }}>Categories</Link>.
            </p>
          ) : (
            safeCategories.map((cat) => {
              const isSelected = selectedCategoryId === cat.id;
              const isCategoriesMode = viewMode === "categories";
              return (
                <div key={cat.id} className="relative flex items-center gap-2 shrink-0">
                  <button
                    type="button"
                    onClick={() => handleCategoryChange(cat.id)}
                    style={{
                      padding: "10px 20px",
                      fontSize: 14,
                      fontWeight: isSelected ? "bold" : "normal",
                      background: isSelected ? COLORS.primary : COLORS.bgPanel,
                      color: "#fff",
                      border:
                        isSelected
                          ? `2px solid ${COLORS.primary}`
                          : `1px solid ${COLORS.borderLight}`,
                      borderRadius: 4,
                      cursor: "pointer",
                      textTransform: "uppercase",
                      letterSpacing: "0.5px",
                      transition: "all 0.2s",
                    }}
                  >
                    {cat.name}
                  </button>
                  {viewMode === "categories" && (
                    <button
                      type="button"
                      onClick={() => handleDeleteCategory(cat)}
                      className="rounded px-2 py-0.5 text-xs text-white"
                      style={{ background: "#ef4444" }}
                    >
                      Delete
                    </button>
                  )}
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* Main content */}
      <div
        className="flex-1 overflow-auto p-5"
        style={{ background: COLORS.bgDark }}
      >
        {viewMode === "categories" ? (
          <div className="text-center" style={{ color: "#666" }}>
            Select a category above to Edit or Delete. Manage subcategories in{" "}
            <Link href="/categories" className="underline" style={{ color: COLORS.primary }}>
              Categories
            </Link>
            .
          </div>
        ) : viewMode === "subcategories" ? (
          <>
            {!currentCategory ? (
              <p style={{ color: "#666" }}>Select a category to manage its subcategories.</p>
            ) : (
              <div
                className="grid gap-4"
                style={{
                  gridTemplateColumns: "repeat(auto-fill, minmax(180px, 1fr))",
                  maxWidth: 900,
                }}
              >
                {subcategories.map((sub, index) => {
                  const colors = TILE_COLORS[index % TILE_COLORS.length];
                  return (
                    <div
                      key={sub.id}
                      className="flex flex-col items-center justify-between rounded-lg p-4"
                      style={{
                        background: COLORS.bgPanel,
                        border: `2px solid ${colors.border}`,
                        minHeight: 100,
                      }}
                    >
                      <span
                        className="text-center font-semibold uppercase"
                        style={{ color: "#fff", letterSpacing: "0.5px" }}
                      >
                        {sub.name}
                      </span>
                      <div className="mt-2 flex gap-2">
                        <button
                          type="button"
                          onClick={() => handleDeleteSubCategory(sub)}
                          className="rounded px-2 py-1 text-xs text-white"
                          style={{ background: "#ef4444" }}
                        >
                          Delete
                        </button>
                      </div>
                    </div>
                  );
                })}
                {subcategories.length === 0 && (
                  <p style={{ color: "#666" }}>
                    No subcategories. Add them in <Link href="/categories" className="underline" style={{ color: COLORS.primary }}>Categories</Link>.
                  </p>
                )}
              </div>
            )}
          </>
        ) : viewMode === "items" ? (
          <>
            {!currentCategory ? (
              <p style={{ color: "#666" }}>Select a category to view subcategories.</p>
            ) : selectedSubCategoryId && selectedSubcategory ? (
              /* Items view */
              <div>
                <button
                  type="button"
                  onClick={handleBackToTiles}
                  className="mb-4 flex items-center gap-2 rounded px-4 py-2 text-sm"
                  style={{
                    background: COLORS.bgPanel,
                    color: "#fff",
                    border: `1px solid ${COLORS.borderLight}`,
                  }}
                >
                  ← Back to Subcategories
                </button>

                <div className="mb-4 flex items-center justify-between">
                  <h3
                    className="border-b pb-2 text-sm font-semibold uppercase tracking-wide"
                    style={{
                      color: "#ddd",
                      borderColor: COLORS.primary,
                    }}
                  >
                    {selectedSubcategory.name}
                  </h3>
                  <Link
                    href={`/items/new?subCategoryId=${selectedSubCategoryId}`}
                    className="rounded px-4 py-2 text-sm font-medium text-white"
                    style={{ background: COLORS.primary }}
                  >
                    Create Item
                  </Link>
                </div>

                {filteredItems.length === 0 ? (
                  <p className="py-8 text-center" style={{ color: "#666" }}>
                    No items in this subcategory.
                  </p>
                ) : (
                  <div
                    className="grid gap-3"
                    style={{
                      gridTemplateColumns: "repeat(auto-fill, minmax(160px, 1fr))",
                    }}
                  >
                    {filteredItems.map((item) => (
                      <div
                        key={item.id}
                        className="group flex flex-col rounded-lg border-2 p-3 transition-colors"
                        style={{
                          background: COLORS.bgPanel,
                          borderColor: item.deletedAt ? "#444" : "#3a3a3a",
                          opacity: item.deletedAt ? 0.75 : 1,
                        }}
                      >
                        {item.imageUrl ? (
                          <img
                            src={
                              item.imageUrl.startsWith("http")
                                ? item.imageUrl
                                : `${API_URL}${item.imageUrl}`
                            }
                            alt=""
                            className="mb-2 h-20 w-full rounded object-cover"
                          />
                        ) : (
                          <div
                            className="mb-2 flex h-20 w-full items-center justify-center rounded text-xs"
                            style={{ background: "#333", color: "#666" }}
                          >
                            No image
                          </div>
                        )}
                        <div
                          className="font-semibold"
                          style={{ color: "#fff", fontSize: 14 }}
                        >
                          {item.name}
                        </div>
                        <div
                          className="text-sm"
                          style={{ color: "#4ade80", fontWeight: 600 }}
                        >
                          {formatPesos(item.priceCents)}
                        </div>
                        {item.deletedAt && (
                          <span className="mt-1 text-xs" style={{ color: "#ef4444" }}>
                            Deleted
                          </span>
                        )}
                        <div className="mt-2 flex gap-2">
                          <Link
                            href={
                              item.deletedAt
                                ? `/items/${item.id}?includeDeleted=1`
                                : `/items/${item.id}`
                            }
                            className="text-xs underline"
                            style={{ color: COLORS.primary }}
                          >
                            Edit
                          </Link>
                          {item.deletedAt ? (
                            <button
                              type="button"
                              onClick={() => handleRestoreItem(item)}
                              className="text-xs underline"
                              style={{ color: "#22c55e" }}
                            >
                              Restore
                            </button>
                          ) : (
                            <button
                              type="button"
                              onClick={() => handleDeleteItem(item)}
                              className="text-xs underline"
                              style={{ color: "#ef4444" }}
                            >
                              Delete
                            </button>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ) : (
              /* Subcategory tiles grid */
              subcategories.length > 0 ? (
                <div
                  className="grid gap-4"
                  style={{
                    gridTemplateColumns: "repeat(3, 1fr)",
                    maxWidth: 900,
                  }}
                >
                  {subcategories.map((sub, index) => {
                    const colors = TILE_COLORS[index % TILE_COLORS.length];
                    return (
                      <button
                        key={sub.id}
                        type="button"
                        onClick={() => handleSubcategoryClick(sub)}
                        className="flex min-h-[120px] flex-col items-center justify-center rounded-lg p-4 transition-all hover:-translate-y-0.5"
                        style={{
                          background: COLORS.bgPanel,
                          border: `2px solid ${colors.border}`,
                        }}
                      >
                        <div
                          className="mb-3 text-center text-sm font-bold uppercase tracking-wide"
                          style={{ color: "#fff", lineHeight: 1.3 }}
                        >
                          {sub.name}
                        </div>
                        <div
                          className="h-0.5 w-10 rounded"
                          style={{ background: colors.accent }}
                        />
                      </button>
                    );
                  })}
                </div>
              ) : (
                <p style={{ color: "#666" }}>
                  No subcategories. Add them in <Link href="/categories" className="underline" style={{ color: COLORS.primary }}>Categories</Link>.
                </p>
              )
            )}
          </>
        ) : null}
      </div>
    </div>
  );
}
